import { useState, useEffect } from "react";
import Buttons from "../Buttons";
import "./screensix.css";
import ProgressBar from "../ProgressBar";
import "./screensix.css"

const ScreenSix = ({ screen, nmscreen, formData, handleInputChange, submitData }) => {
  const [clicked, setClicked] = useState(false);
  const [achievements, setAchievements] = useState(formData.achievements || "");
  const [meetingsPerMonth, setMeetingsPerMonth] = useState(formData.meetingsPerMonth || null);

  useEffect(() => {
    setAchievements(formData.achievements || "");
    setMeetingsPerMonth(formData.meetingsPerMonth || null);
  }, [formData]);

  const handleMeetingClick = (num) => {
    setMeetingsPerMonth(num);
    handleInputChange("meetingsPerMonth", num);
  };

  const handleAchievementsChange = (e) => {
    setAchievements(e.target.value);
    handleInputChange("achievements", e.target.value);
  };

  const handleNext = () => {
    submitData(formData); // Simulated submission
    setTimeout(() => {
      screen("screen7", 7); // Navigate to screen7 after submission
    }, 1000); // Adjust timing as needed for your submission process
  };

  return (
    <div id="screen6">
      <div className="section1">
        <h1 className="title">What are you hoping to achieve with our service?</h1>
        <textarea
          name="answer"
          id="answer-screen6"
          className={clicked ? "clicked" : ""}
          placeholder="Enter your message here.."
          onClick={() => {
            setClicked(true);
          }}
          value={achievements}
          onChange={handleAchievementsChange}
        ></textarea>
      </div>
      <div className="section2">
        <h1 className="title">How many meetings per month would you like to have?</h1>
        <div className="buttons-of-input">
          <p className={meetingsPerMonth === 1 ? "clicked" : ""} onClick={() => handleMeetingClick(1)}>
            1
          </p>
          <p className={meetingsPerMonth === 2 ? "clicked" : ""} onClick={() => handleMeetingClick(2)}>
            2-3
          </p>
          <p className={meetingsPerMonth === 3 ? "clicked" : ""} onClick={() => handleMeetingClick(3)}>
            4
          </p>
        </div>
      </div>
      <Buttons changeScreen={screen} back={"screen5"} next={handleNext} nb={5} nn={7} />
    </div>
  );
};

export default ScreenSix;
